import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";
import process from "node:process";

const rootDir = process.cwd();
const packageJsonPath = resolve(rootDir, "package.json");
const outputPath = resolve(rootDir, "src/generated/package-metadata.ts");

const packageMetadata = JSON.parse(readFileSync(packageJsonPath, "utf8"));

const content = [
  "// This file is generated by scripts/sync-package-metadata.mjs.",
  "// Do not edit it manually.",
  `export const DEVFORGE_VERSION = ${JSON.stringify(packageMetadata.version ?? "0.0.0")};`,
  `export const DEVFORGE_PACKAGE_NAME = ${JSON.stringify(packageMetadata.name ?? "@ali-dev11/devforge")};`,
  `export const DEVFORGE_AUTHOR = ${JSON.stringify(packageMetadata.author ?? "Ali-dev11")};`,
  "",
].join("\n");

mkdirSync(resolve(rootDir, "src/generated"), { recursive: true });
writeFileSync(outputPath, content, "utf8");
